// Sample customer data — 12 records including edge cases.
const customers = [
  { id: 'C001', company: 'Globex Corp', segment: 'enterprise', employees: 1200, industry: 'manufacturing', region: 'US', arr: 24000, status: 'active', months_retained: 18 },
  { id: 'C002', company: 'Initech LLC', segment: 'smb', employees: 45, industry: 'software', region: 'US', arr: 3600, status: 'active', months_retained: 6 },
  { id: 'C003', company: 'Umbrella Ltd', segment: 'mid-market', employees: 320, industry: 'healthcare', region: 'EU', arr: 12000, status: 'active', months_retained: 24 },
  { id: 'C004', company: 'Hooli Inc', segment: 'enterprise', employees: 5000, industry: 'technology', region: 'US', arr: 60000, status: 'churned', months_retained: 8 },
  { id: 'C005', company: 'Pied Piper', segment: 'startup', employees: 12, industry: 'software', region: 'US', arr: 1200, status: 'active', months_retained: 14 },
  { id: 'C006', company: 'Dunder Mifflin', segment: 'smb', employees: 90, industry: 'retail', region: 'US', arr: 4800, status: 'active', months_retained: 11 },
  { id: 'C007', company: 'Vandelay Ind', segment: 'mid-market', employees: 450, industry: 'finance', region: 'EU', arr: 9600, status: 'active', months_retained: 20 },
  { id: 'C008', company: 'Sterling Cooper', segment: 'enterprise', employees: 2200, industry: 'marketing', region: 'US', arr: 36000, status: 'churned', months_retained: 5 },
  { id: 'C009', company: 'Wernham Hogg', segment: 'smb', employees: 75, industry: 'logistics', region: 'UK', arr: 2400, status: 'active', months_retained: 9 },
  { id: 'C010', company: 'Sabre Corp', segment: 'enterprise', employees: 800, industry: 'technology', region: 'US', arr: 18000, status: 'active', months_retained: 30 },
  { id: 'C011', company: 'Slate Rock', segment: 'smb', employees: 30, industry: 'construction', region: 'US', arr: 2400, status: 'active', months_retained: 4 },
  { id: 'C012', company: '', segment: '', employees: null, industry: '', region: '', arr: null, status: 'active', months_retained: null }
];
return customers.map(c => ({ json: c }));

// Aggregate and analyse customer distribution vs stated ICP.
const all = $input.all().map(i => i.json);
const valid = all.filter(c => c.id && c.segment && c.status);
const skipped = all.length - valid.length;
const icpDefinition = $env.ICP_DEFINITION || 'B2B SaaS, 50-500 employees, software/technology industry, US or EU, mid-market or SMB segment';

// Compute distributions
const countBy = (field) => {
  const counts = {};
  for (const c of valid) {
    const key = String(c[field] || 'unknown');
    counts[key] = (counts[key] || 0) + 1;
  }
  return counts;
};

const pct = (count, total) => Math.round((count / total) * 100);

const total = valid.length;
const active = valid.filter(c => c.status === 'active').length;
const churned = valid.filter(c => c.status === 'churned').length;

const segmentDist = countBy('segment');
const industryDist = countBy('industry');
const regionDist = countBy('region');

// Compute avg employees for active vs churned
const avgEmployees = (arr) => {
  const nums = arr.filter(c => c.employees > 0).map(c => c.employees);
  return nums.length ? Math.round(nums.reduce((a,b)=>a+b,0)/nums.length) : null;
};
const avgEmpActive = avgEmployees(valid.filter(c => c.status === 'active'));
const avgEmpChurned = avgEmployees(valid.filter(c => c.status === 'churned'));

// Flag divergence: check if top segment, top industry, and top region match ICP
const topSegment = Object.entries(segmentDist).sort((a,b)=>b[1]-a[1])[0]?.[0];
const topIndustry = Object.entries(industryDist).sort((a,b)=>b[1]-a[1])[0]?.[0];
const topRegion = Object.entries(regionDist).sort((a,b)=>b[1]-a[1])[0]?.[0];

const report = [
  `ICP DRIFT DETECTOR`,
  `Stated ICP: ${icpDefinition}`,
  `Run: ${new Date().toISOString()} | Customers analysed: ${valid.length} (${skipped} skipped)`,
  `Active: ${active} | Churned: ${churned} | Churn rate: ${pct(churned, total)}%`,
  ``,
  `SEGMENT DISTRIBUTION (% of total):`,
  ...Object.entries(segmentDist).map(([k,v]) => `  ${k}: ${pct(v,total)}% (${v} customers)`),
  ``,
  `INDUSTRY DISTRIBUTION:`,
  ...Object.entries(industryDist).map(([k,v]) => `  ${k}: ${pct(v,total)}% (${v} customers)`),
  ``,
  `REGION DISTRIBUTION:`,
  ...Object.entries(regionDist).map(([k,v]) => `  ${k}: ${pct(v,total)}% (${v} customers)`),
  ``,
  `EMPLOYEE SIZE:`,
  `  Active customers avg employees: ${avgEmpActive || 'N/A'}`,
  `  Churned customers avg employees: ${avgEmpChurned || 'N/A'}`,
  ``,
  `DRIFT FLAGS:`,
  `  Top actual segment: ${topSegment} (ICP target: check stated ICP)`,
  `  Top actual industry: ${topIndustry} (ICP target: check stated ICP)`,
  `  Top actual region: ${topRegion} (ICP target: check stated ICP)`,
  ``,
  `NOTE: Automated drift scoring requires defining ICP numerically (see README). This report shows raw distributions for human review.`
].join('\n');

return [{ json: {
  report_text: report,
  stats: { total, active, churned, skipped, segmentDist, industryDist, regionDist, avgEmpActive, avgEmpChurned, topSegment, topIndustry, topRegion },
  icp_definition: icpDefinition,
  generated_at: new Date().toISOString()
} }];
